{
  "summary": "This paper proposes IAPEK, an instance-level adaptive framework that selectively injects external knowledge into pre-trained language models (PTLMs) guided by a novel metric called Thrust, which estimates the necessity of external knowledge based on clustering training instance embeddings. Extensive experiments on a large-scale benchmark of 12 NLP tasks demonstrate that Thrust-guided selective knowledge injection improves both performance and efficiency compared to naive full knowledge injection.",
  "strengths": [
    {
      "point": "Novel adaptive knowledge injection framework",
      "evidence": "IAPEK adaptively decides per-instance whether to inject external knowledge, addressing noise and inefficiency in knowledge-enhanced PTLMs."
    },
    {
      "point": "Introduction of the Thrust metric",
      "evidence": "Thrust is a lightweight, unsupervised metric leveraging clustering of training instance embeddings to estimate the necessity of external knowledge without requiring test labels or additional fine-tuning."
    },
    {
      "point": "Comprehensive benchmark and evaluation",
      "evidence": "The authors curated a large-scale benchmark spanning 12 diverse NLP tasks with multiple knowledge sources, enabling systematic evaluation of external knowledge usage and adaptive injection."
    },
    {
      "point": "Empirical demonstration of improved performance and efficiency",
      "evidence": "Thrust-guided selective knowledge injection yields an average 26% performance improvement over naive knowledge injection on 88% of evaluated cases, while reducing computational cost."
    },
    {
      "point": "Insightful analysis of external knowledge usage",
      "evidence": "The paper shows that large PTLMs do not always benefit from external knowledge and that fine-tuning on knowledge-augmented data enhances knowledge utilization, highlighting the importance of adaptive retrieval."
    }
  ],
  "weaknesses": [
    {
      "point": "Insufficient comparison to prior adaptive knowledge retrieval methods",
      "evidence": "The paper lacks explicit citations and empirical comparisons to established adaptive or confidence-based retrieval approaches such as uncertainty sampling, gating mechanisms, or recent dynamic retrieval methods like REALM or RAG variants."
    },
    {
      "point": "Methodological gaps in clustering approach",
      "evidence": "There is no justification for choosing K-means over other clustering algorithms, no discussion or ablation on the number of clusters (K), and unclear whether clustering is static or updated, which affects the reliability and practicality of Thrust."
    },
    {
      "point": "Limited quantitative analysis on embedding layer sensitivity and model variants",
      "evidence": "Although a layer ablation is mentioned, detailed quantitative results on how embedding layer choice or different PTLM architectures affect Thrust's robustness are missing."
    },
    {
      "point": "Evaluation lacks adaptive retrieval baselines and statistical rigor",
      "evidence": "The evaluation compares mainly against naive full knowledge injection, omitting comparisons to other adaptive baselines and does not report statistical significance or variance measures for performance gains."
    },
    {
      "point": "Reproducibility concerns due to missing implementation details and resource release",
      "evidence": "Critical details on clustering hyperparameters, embedding dimensionality, and algorithmic steps are absent, and there is no mention of public release of code, datasets, or knowledge sources."
    },
    {
      "point": "Clarity issues in Thrust metric formulation and threshold selection",
      "evidence": "The mathematical description of Thrust is abstract without formal equations or pseudocode, and the threshold for knowledge injection lacks explanation or sensitivity analysis."
    },
    {
      "point": "Limited discussion on limitations and generalizability",
      "evidence": "The paper does not address dynamic or evolving knowledge bases, potential biases from training distribution clustering, out-of-distribution robustness, cross-lingual or cross-domain applicability, or scalability to very large knowledge bases and real-time systems."
    },
    {
      "point": "Missing analyses on computational overhead and impact of knowledge noise",
      "evidence": "The computational cost of clustering and Thrust computation is not quantified, nor is the effect of varying external knowledge noise or quality on Thrust's decision accuracy studied."
    }
  ],
  "questions": [
    {
      "question": "How does Thrust compare empirically to existing adaptive or confidence-based knowledge retrieval methods?",
      "motivation": "Understanding relative performance against established baselines is critical to validate the claimed novelty and practical advantage of Thrust."
    },
    {
      "question": "How sensitive is Thrust to the choice of clustering algorithm, number of clusters, and embedding layer?",
      "motivation": "These factors directly impact the metric's reliability and robustness, affecting reproducibility and applicability across different models and tasks."
    },
    {
      "question": "Can the method adapt to dynamic or evolving knowledge bases and handle out-of-distribution queries effectively?",
      "motivation": "Real-world deployment requires robustness to changing knowledge sources and diverse input distributions, which are not addressed."
    },
    {
      "question": "What is the computational overhead of embedding, clustering, and Thrust computation relative to the efficiency gains from selective knowledge injection?",
      "motivation": "Quantifying runtime and resource costs is essential to assess practical feasibility, especially for large-scale or real-time applications."
    },
    {
      "question": "Will releasing code, datasets, and knowledge indices be possible to facilitate reproducibility and community adoption?",
      "motivation": "Availability of resources is crucial for verifying results and enabling further research building on this work."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
